\nimport \'package:firebase_messaging/firebase_messaging.dart\';\nimport \'package:flutter/foundation.dart\';\nimport \'package:myapp/services/firestore_service.dart\';\n\n// Handles background messages\n@pragma(\'vm:entry-point\')\nFuture<void> _firebaseMessagingBackgroundHandler(RemoteMessage message) async {\n  // If you\'re going to use other Firebase services in the background, such as Firestore,\n  // make sure you call `initializeApp` before using other Firebase services.\n  // await Firebase.initializeApp(); // Already done in main\n\n  print(\"Handling a background message: \${message.messageId}\");\n  // Here you can process the message data.\n}\n\nclass PushNotificationService {\n  final FirebaseMessaging _fcm = FirebaseMessaging.instance;\n  final FirestoreService _firestoreService;\n\n  PushNotificationService(this._firestoreService);\n\n  Future<void> initialize() async {\n    // Request permissions for iOS/web/newer Android\n    NotificationSettings settings = await _fcm.requestPermission(\n      alert: true,\n      announcement: false,\n      badge: true,\n      carPlay: false,\n      criticalAlert: false,\n      provisional: false,\n      sound: true,\n    );\n\n    if (kDebugMode) {\n      print(\'Permission granted: \${settings.authorizationStatus}\');\n    }\n\n    // Get the FCM token\n    final String? token = await _fcm.getToken();\n    if (token != null) {\n      print(\"FCM Token: $token\");\n      // Save the token to Firestore associated with the user\n      await _saveTokenToDatabase(token);\n    }\n\n    // Listen for token refresh\n    _fcm.onTokenRefresh.listen(_saveTokenToDatabase);\n\n    // Set up message handlers\n    _setupMessageHandlers();\n  }\n\n  Future<void> _saveTokenToDatabase(String token) async {\n    // Get the current user ID. If not logged in, we can\'t save the token.\n    final userId = _firestoreService.getCurrentUserId();\n    if (userId != null) {\n      await _firestoreService.saveUserToken(token, userId);\n    }\n  }\n\n  void _setupMessageHandlers() {\n    // Handles messages when the app is in the foreground.\n    FirebaseMessaging.onMessage.listen((RemoteMessage message) {\n      print(\'Got a message whilst in the foreground!\');\n      print(\'Message data: \${message.data}\');\n\n      if (message.notification != null) {\n        print(\'Message also contained a notification: \${message.notification}\');\n        // Here you could show a local notification using a package like `flutter_local_notifications`\n        // to make sure the user sees it while they are in the app.\n      }\n    });\n\n    // Handles when a user taps a notification and opens the app from a background state.\n    FirebaseMessaging.onMessageOpenedApp.listen((RemoteMessage message) {\n      print(\'Message opened from background: \${message.data}\');\n      // Navigate to a specific screen based on message data, e.g., a new chapter.\n    });\n    \n    // Handles a notification that opened the app from a terminated state.\n    FirebaseMessaging.instance.getInitialMessage().then((RemoteMessage? message) {\n       if (message != null) {\n          print(\'Message opened from terminated state: \${message.data}\');\n          // Navigate to a specific screen.\n       }\n    });\n\n    // Set the background message handler.\n    FirebaseMessaging.onBackgroundMessage(_firebaseMessagingBackgroundHandler);\n  }\n}\n